     3→ * file, You can obtain one at https://mozilla.org/MPL/2.0/. */
     4→
     5→use std::cell::RefCell;
     6→
     7→use cssparser::SourceLocation;
     8→use servo_arc::Arc;
     9→use style::context::QuirksMode;
    10→use style::error_reporting::{ContextualParseError, ParseErrorReporter};
    11→use style::media_queries::MediaList;
    12→use style::shared_lock::SharedRwLock;
    13→use style::stylesheets::{
    14→    AllowImportRules, Origin, Stylesheet, StylesheetInDocument, UrlExtraData,
    15→};
    16→use url::Url;
    17→
    18→#[derive(Debug)]
    19→struct CSSError {
    20→    pub url: Arc<Url>,
    21→    pub line: u32,
    22→    pub column: u32,
    23→    pub message: String,
    24→}
    25→
    26→struct TestingErrorReporter {
    27→    errors: RefCell<Vec<CSSError>>,
    28→}
    29→
    30→impl TestingErrorReporter {
    31→    pub fn new() -> Self {
    32→        TestingErrorReporter {
    33→            errors: RefCell::new(Vec::new()),
    34→        }
    35→    }
    36→
    37→    fn assert_messages_contain(&self, expected_errors: &[(u32, u32, &str)]) {
    38→        let errors = self.errors.borrow();
    39→        for (i, (error, &(line, column, message))) in errors.iter().zip(expected_errors).enumerate()
    40→        {
    41→            assert_eq!(
    42→                (error.line, error.column),
    43→                (line, column),
    44→                "line/column numbers of the {}th error: {:?}",
    45→                i + 1,
    46→                error.message
    47→            );
    48→            assert!(
    49→                error.message.contains(message),
    50→                "{:?} does not contain {:?}",
    51→                error.message,
    52→                message
    53→            );
    54→        }
    55→        if errors.len() < expected_errors.len() {
    56→            panic!("Missing errors: {:#?}", &expected_errors[errors.len()..]);
    57→        }
    58→        if errors.len() > expected_errors.len() {
    59→            panic!("Extra errors: {:#?}", &errors[expected_errors.len()..]);
    60→        }
    61→    }
    62→}
    63→
    64→impl ParseErrorReporter for TestingErrorReporter {
    65→    fn report_error(
    66→        &self,
    67→        url: &UrlExtraData,
    68→        location: SourceLocation,
    69→        error: ContextualParseError,
    70→    ) {
    71→        self.errors.borrow_mut().push(CSSError {
    72→            url: url.0.clone(),
    73→            line: location.line,
    74→            column: location.column,
    75→            message: error.to_string(),
    76→        })
    77→    }
    78→}
    79→
    80→#[test]
    81→fn test_report_error_stylesheet() {
    82→    let css = r"
    83→    div {
    84→        background-color: red;
    85→        display: invalid;
    86→        background-image: linear-gradient(0deg, black, invalid, transparent);
    87→        invalid: true;
    88→    }
    89→    @media (min-width: 10px invalid 1000px) {}
    90→    @font-face { src: url(), invalid, url(); }
    91→    @counter-style foo { symbols: a 0invalid b }
    92→    @font-feature-values Sans Sans { @foo {} @swash { foo: 1 invalid 2 } }
    93→    @invalid;
    94→    @media screen { @invalid; }
    95→    @supports (color: green) and invalid and (margin: 0) {}
    96→    @keyframes foo { from invalid {} to { margin: 0 invalid 0; } }
    97→    ";
    98→    let url = Url::parse("about::test").unwrap();
    99→    let error_reporter = TestingErrorReporter::new();
   100→
   101→    let lock = SharedRwLock::new();
   102→    let media = Arc::new(lock.wrap(MediaList::empty()));
   103→    Stylesheet::from_str(
   104→        css,
   105→        url.clone().into(),
   106→        Origin::UserAgent,
   107→        media,
   108→        lock,
   109→        None,
   110→        Some(&error_reporter),
   111→        QuirksMode::NoQuirks,
   112→        AllowImportRules::Yes,
   113→    );
   114→
   115→    error_reporter.assert_messages_contain(&[
   116→        (
   117→            3,
   118→            18,
   119→            "Unsupported property declaration: 'display: invalid;'",
   120→        ),
   121→        (
   122→            4,
   123→            43,
   124→            "Unsupported property declaration: 'background-image:",
   125→        ), // FIXME: column should be around 56
   126→        (5, 17, "Unsupported property declaration: 'invalid: true;'"),
   127→        (7, 28, "Invalid media rule"),
   128→        // When @counter-style is supported, this should be replaced with two errors
   129→        (9, 19, "Invalid rule: '@counter-style "),
   130→        // When @font-feature-values is supported, this should be replaced with two errors
   131→        (10, 25, "Invalid rule: '@font-feature-values "),
   132→        (11, 13, "Invalid rule: '@invalid'"),
   133→        (12, 29, "Invalid rule: '@invalid'"),
   134→        (13, 34, "Invalid rule: '@supports "),
   135→        (14, 26, "Invalid keyframe rule: 'from invalid '"),
   136→        (
   137→            14,
   138→            52,
   139→            "Unsupported property declaration: 'margin: 0 invalid 0;'",
   140→        ),
   141→    ]);
   142→
   143→    assert_eq!(*error_reporter.errors.borrow()[0].url, url);
   144→}
   145→
   146→#[test]
   147→fn test_no_report_unrecognized_vendor_properties() {
   148→    let css = r"
   149→    div {
   150→        -o-background-color: red;
   151→        _background-color: red;
   152→        -moz-background-color: red;
   153→    }
   154→    ";
   155→    let url = Url::parse("about::test").unwrap();
   156→    let error_reporter = TestingErrorReporter::new();
   157→
   158→    let lock = SharedRwLock::new();
   159→    let media = Arc::new(lock.wrap(MediaList::empty()));
   160→    Stylesheet::from_str(
   161→        css,
   162→        url.into(),
   163→        Origin::UserAgent,
   164→        media,
   165→        lock,
